var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"예상외의 전개라고 할까요? 아니면 운명이라고 해야 할까요?","JPN":"予想外の展開というべきでしょうか。それとも運命というべきでしょうか。","ENG":"What an unexpected turn of events. Or is this too fate?","TWN":"該說是意料之外的發展嗎？還是說這是命運呢？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마지막에 저를 가로막는 게 하필 <color=#ffd34c>사자자리</color>인 당신이라니.","JPN":"最後に私の前に立ちはだかるのが、よりによって<color=#ffd34c>獅子座</color>のあなただなんて。","ENG":"The last to stand in my way had to be you. A <color=#ffd34c>Leo</color>.","TWN":"最後擋在我面前的，偏偏是你這個<color=#ffd34c>獅子座</color>。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시니어의 죽음이 공표된 지 반나절도 지나지 않았어요. 어떻게 이렇게 빨리 도착한 거죠?","JPN":"シニアの死が公表されてから半日も経ってないのに、どうやってこんなに早く私を見つけたのですか？","ENG":"Not even half a day has passed since Senior's death. How did you get here so quickly?","TWN":"Senior的死訊剛公佈不到半天。你怎麼這麼快就到了？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"글쎄, 그러기에는 이미 실수를 저지르지 않았어?","JPN":"どうかしら。その割にはもうミスってない？","ENG":"Well, didn't you already make a mistake before that?","TWN":"嗯，你已經漏出馬腳了，不是嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"실수……?","JPN":"ミス……？","ENG":"A mistake...?","TWN":"我……？失誤了嗎……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"얼마 전에 이상한 경험을 했단 말이지.","JPN":"この前、おかしなことがあってね。","ENG":"I had a strange experience a few days ago.","TWN":"前段時間我經歷了一件奇怪的事。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"샤레이드 대균열에서 발생한 침식 현상을 누군가가 나 대신 처리해 버렸더라고.","JPN":"シャレード大亀裂で発生した侵食現象を、誰かが私の代わりに処理しちゃったの。","ENG":"When a Counterside Effect occurred in Charade's Grand Dimension Crevice, someone took care of it instead of me.","TWN":"有人在查雷德大峽谷處理了侵蝕現象，替我解決了麻煩。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"귀찮은 일이 줄어서 그때는 좋아라 했는데, 생각해보니까 이상하더라?","JPN":"あの時は面倒ごとが減って嬉しかったけど、よくよく考えてみると変なのよ。","ENG":"I was glad at the time that it was one less annoying chore off my list, but the more I thought about it the weirder it got.","TWN":"當時我還挺高興少了件麻煩事，但仔細想想，覺得有點奇怪。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"샤레이드에서 대가 없이 호의를 베푸는 멍청이는 없단 말이지.","JPN":"シャレードで何の意味もなく人を助けるアホなんて、いるわけないのに。","ENG":"No one in Charade is foolish enough to give out favors without something in return.","TWN":"在查雷德，可沒有人會無償施以恩惠。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서 리하르트가 죽었다는 이야기를 들었을 때, 바로 여기 올 수 있었던 거야.","JPN":"だからリヒャルトが死んだって話を聞いた時、すぐここまで来られたの。","ENG":"So, when I heard Richard was dead, I could get here right away.","TWN":"所以當我聽到理查死了的消息時，才能馬上趕到這裡。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"날 사칭한 범인이 리하르트를 죽였다면, 다른 도시의 대균열에도 볼일이 있을지 모르니까.","JPN":"私を名乗った犯人がリヒャルトを殺したとしら、違う都市の大亀裂にも手出しをするかもしれないから。","ENG":"If the culprit who impersonated me killed Richard, then this person must have similar business in the Grand Dimension Crevices of other cities, no?","TWN":"如果冒充我的犯人殺了理查，那他可能還會在其他城市的大峽谷中有所行動。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대균열이라면 샤레이드 말고도 다섯 군데가 더 있었을 텐데요?","JPN":"大亀裂ならシャレードの他にも五か所もあったはずです。","ENG":"But there are five other Grand Dimension Crevices besides Charade.","TWN":"而說到大峽谷的話，除了查雷德還有五個地方吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어떻게 제가 로터스 대균열을 노릴 걸 미리 예측한 거죠?","JPN":"どうやって私がロータス大亀裂を狙うとわかったのですか？","ENG":"How did you know I would target the one in Lotus?","TWN":"那你是怎麼預料到我會盯上洛德斯大峽谷的？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어, 그냥 그럴 것 같았어~","JPN":"うーん、なんとなく～？","ENG":"Oh, that? Just a hunch.","TWN":"喔，我想也是~"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"여자의 직감이라고 할까나? 어쨌든 맞췄으니까 됐잖아?","JPN":"女の勘っていうのかしら？　とにかく当てたんだからいいじゃない？","ENG":"A woman's intuition, if you will? But who cares? I got it right, didn't I?","TWN":"應該女人的直覺吧？反正猜對了，不是嗎~？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 재미있네요.","JPN":"ふふ、面白いですね。","ENG":"Haha. That's interesting.","TWN":"呵呵，有意思呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신에 대한 제 해석이 틀렸군요. 당신을 연기할 때 좀 더 주의할 걸 그랬네요.","JPN":"あなたに対する解釈が間違っていました。あなたを演じるときにもっと気をつけるべきでしたね。","ENG":"It seems my interpretation of you was wrong. I should have paid more attention while acting as you.","TWN":"看來我對你的理解有誤。扮演你的時候應該更小心一些。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서? 리하르트의 복수라도 할 셈인가요. 당신은 그런 캐릭터가 아닐 텐데요?","JPN":"で？　リヒャルトの敵討ちでもするつもりですか？　あなたはそういうキャラクターではないはずですが。","ENG":"So? Are you going to avenge Richard? That doesn't seem like you, though.","TWN":"那麼？你打算為理查復仇嗎？你可不是那種角色吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"복수라……? 글쎄, 잘 모르겠네?","JPN":"敵討ち、ねぇ……？　さあ、どうだか。","ENG":"Avenge? Hmm, I'm not so sure.","TWN":"復仇嗎……？嗯，我還真不知道呢？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"애초에 현실의 사람이 작품 속 캐릭터처럼 딱딱 들어 맞게 행동할 리 없잖아?","JPN":"そもそも現実の人間って、創作物のキャラクターとは違うのよ。そんな設定どおりに動きなさい、みたいなこと言われてもね。","ENG":"Then again, no one in the real world acts exactly like characters in a play, right?","TWN":"本來現實中的人物就不可能像作品中的角色那樣完美行動。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"귀찮은 아저씨였어. 사춘기 지난 지가 언젠데, 맨날 잔소리나 해대고 말이야.","JPN":"面倒くさいおじさんだったわ。とっくに思春期も終わったのに、いつも小言を言われたし。","ENG":"He was an annoying guy. He always nagged me as if I were still young child.","TWN":"你也這麼覺得吧？那個大叔煩得要死，明明青春期早就過了，但就是天天嘮叨個不停。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"누가 군인 출신 아니랄까 봐, 앞뒤 꽉 막혀가지고.","JPN":"元軍人だからか、頭固くて。","ENG":"Like we don't know he's an ex-soldier. So stuffy, you know?","TWN":"還生怕有人不知道他的軍人出身，做事死板得很。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그러게 뇌물 좀 받아먹고, 기업들 뒤치다꺼리해주면, 서로가 윈윈인데 얼마나 좋아?","JPN":"少しぐらいは？　賄賂も受け取って、企業の尻ぬぐいも引き受けて。適当に融通利かせたらお互い得するのにね。","ENG":"It would've been a win-win for everyone involved if he took some bribes and helped out around the companies, don't you think?","TWN":"你看，賺點外快，幫企業擦屁股，大家雙贏，多好啊？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래도…….","JPN":"でも……","ENG":"But still...","TWN":"不過……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아니, 그러니까 그 망할 도시에는 꼭 필요한 사람이었어.","JPN":"いや、だからあのクソみたいな都市には絶対必要な人だったのよ。","ENG":"No, that's exactly why this damned city needed someone like him.","TWN":"不，我的意思是，他是那座該死的城市裡不可或缺的人。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐, 감상적인 이야기는 이쯤하자고.","JPN":"まあ、感傷的になるのもここまでにして。","ENG":"Well, that's enough of sentimental stories for today.","TWN":"好了，感傷的話就到此為止吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"피차 바쁜 상황이잖아? 안 그래?","JPN":"あなたも忙しいんでしょう？　違う？","ENG":"We're both busy, no?","TWN":"大家都很忙，不是嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"오만하군요. 아무리 관리국 공인 S급 카운터라고 해도, 혼자서는 절 막기 힘들 겁니다.","JPN":"傲慢ですね。いくら管理局公認のS級カウンターであっても、一人で私を食い止めるには荷が重いのでは？","ENG":"How arrogant. Even if you are an Administration confirmed Grade S Counter, it'll prove difficult to take me on by yourself.","TWN":"真是傲慢啊。即使你是管理局公認的S級制裁者，一個人也阻止不了我。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"게다가 당신은 이제 챔피언이라는 타이틀도 내려 놓게 되었죠.","JPN":"それにあなたはもうチャンピオンのタイトルも失っている。","ENG":"Plus, you have laid down your title as champion.","TWN":"而且你現在摘下了冠軍的頭銜。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"더는 명예롭지 않은 <color=#ffd34c>오지만디아스</color>라는 이름에 무슨 의미가 있죠?","JPN":"名誉をなくした<color=#ffd34c>オジマンディアス</color>という名に、何の意味があるのですか？","ENG":"What more meaning would the dishonorable name <color=#ffd34c>Ozymandias</color> have now?","TWN":"當<color=#ffd34c>奧茲曼迪亞斯</color>不再榮耀了，這個名字還有什麼意義呢？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"명예?","JPN":"名誉？","ENG":"Honor?","TWN":"榮耀？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 이거 같은 엔터테이너로서 실망이네~","JPN":"ふふ、同じエンターテイナーとしてガッカリだわ～","ENG":"Haha, I'm a little disappointed in you as an entertainer.","TWN":"呵呵，作為同樣的藝人，真是讓人失望啊~"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"명예는 지키는 게 아니라 쟁취할 때.","JPN":"名誉は守る時じゃなくて勝ち取る時に、","ENG":"You earn honor, not protect it.","TWN":"榮耀不是用來守護的，而是用來爭取的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그리고 승부는 챔피언일 때보다, 챌린저일 때 더 재밌는 법이라고?","JPN":"そして勝負はチャンピオンの時より、チャレンジャーの時のほうが面白いものなの。","ENG":"And matches are more fun when you're the challenger and not the champion, you know.","TWN":"而且，挑戰者的勝利比冠軍的勝利更有趣，不是嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};